import{_ as a,c as s,o as t,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"故障排查: 表格格式化问题 | opencode-md-table-formatter","description":"学习快速诊断和解决表格格式化问题。涵盖配置错误、无效结构、版本要求和已知限制，提供详细的症状诊断和解决方案。","frontmatter":{"title":"故障排查: 表格格式化问题 | opencode-md-table-formatter","sidebarTitle":"故障排查","subtitle":"故障排查: 表格格式化问题","description":"学习快速诊断和解决表格格式化问题。涵盖配置错误、无效结构、版本要求和已知限制，提供详细的症状诊断和解决方案。","tags":["troubleshooting","FAQ"],"prerequisite":["start-getting-started"],"order":60},"headers":[],"relativePath":"franlol/opencode-md-table-formatter/faq/troubleshooting/index.md","filePath":"franlol/opencode-md-table-formatter/faq/troubleshooting/index.md"}'),n={name:"franlol/opencode-md-table-formatter/faq/troubleshooting/index.md"};function o(l,e,r,p,d,h){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="faq-tables-not-formatting-troubleshooting-guide" tabindex="-1">FAQ: Tables Not Formatting? Troubleshooting Guide <a class="header-anchor" href="#faq-tables-not-formatting-troubleshooting-guide" aria-label="Permalink to &quot;FAQ: Tables Not Formatting? Troubleshooting Guide&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>This lesson will help you quickly diagnose and resolve common issues when using the plugin:</p><ul><li>Identify why tables aren&#39;t formatting</li><li>Understand the meaning of &quot;invalid structure&quot; errors</li><li>Learn about the plugin&#39;s known limitations and scenarios where it doesn&#39;t apply</li><li>Quickly verify if your configuration is correct</li></ul><hr><h2 id="problem-1-tables-not-formatting-automatically" tabindex="-1">Problem 1: Tables Not Formatting Automatically <a class="header-anchor" href="#problem-1-tables-not-formatting-automatically" aria-label="Permalink to &quot;Problem 1: Tables Not Formatting Automatically&quot;">​</a></h2><h3 id="symptoms" tabindex="-1">Symptoms <a class="header-anchor" href="#symptoms" aria-label="Permalink to &quot;Symptoms&quot;">​</a></h3><p>AI generated a table, but column widths are inconsistent and not aligned.</p><h3 id="possible-causes-and-solutions" tabindex="-1">Possible Causes and Solutions <a class="header-anchor" href="#possible-causes-and-solutions" aria-label="Permalink to &quot;Possible Causes and Solutions&quot;">​</a></h3><h4 id="cause-1-plugin-not-configured" tabindex="-1">Cause 1: Plugin Not Configured <a class="header-anchor" href="#cause-1-plugin-not-configured" aria-label="Permalink to &quot;Cause 1: Plugin Not Configured&quot;">​</a></h4><p><strong>Check Steps</strong>:</p><ol><li>Open the <code>.opencode/opencode.jsonc</code> file</li><li>Confirm the plugin is in the <code>plugin</code> array:</li></ol><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@franlol/opencode-md-table-formatter@0.0.3&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><ol start="3"><li>If not, add the plugin configuration</li><li><strong>Restart OpenCode</strong> to make the configuration take effect</li></ol><div class="tip custom-block"><p class="custom-block-title">Configuration Format</p><p>Ensure the version number and package name are correct. Use the format <code>@franlol/opencode-md-table-formatter</code> + <code>@</code> + version number.</p></div><h4 id="cause-2-opencode-not-restarted" tabindex="-1">Cause 2: OpenCode Not Restarted <a class="header-anchor" href="#cause-2-opencode-not-restarted" aria-label="Permalink to &quot;Cause 2: OpenCode Not Restarted&quot;">​</a></h4><p><strong>Solution</strong>:</p><p>After adding the plugin, you must completely restart OpenCode (not just refresh the page) for the plugin to load.</p><h4 id="cause-3-table-missing-separator-row" tabindex="-1">Cause 3: Table Missing Separator Row <a class="header-anchor" href="#cause-3-table-missing-separator-row" aria-label="Permalink to &quot;Cause 3: Table Missing Separator Row&quot;">​</a></h4><p><strong>Symptom Example</strong>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Name | Age |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Alice | 25 |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Bob | 30 |</span></span></code></pre></div><p>This type of table won&#39;t be formatted.</p><p><strong>Solution</strong>:</p><p>Add a separator row (second row, using <code>|---|</code> format):</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Name | Age |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">|--- | ---|</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Alice | 25 |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Bob | 30 |</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Purpose of Separator Row</p><p>The separator row is standard Markdown syntax used to distinguish header rows from content rows, and also to specify alignment. The plugin <strong>must</strong> detect a separator row before formatting the table.</p></div><h4 id="cause-4-opencode-version-too-low" tabindex="-1">Cause 4: OpenCode Version Too Low <a class="header-anchor" href="#cause-4-opencode-version-too-low" aria-label="Permalink to &quot;Cause 4: OpenCode Version Too Low&quot;">​</a></h4><p><strong>Check Steps</strong>:</p><ol><li>Open the OpenCode help menu</li><li>Check the current version number</li><li>Confirm version &gt;= 1.0.137</li></ol><p><strong>Solution</strong>:</p><p>Upgrade to the latest version of OpenCode.</p><div class="warning custom-block"><p class="custom-block-title">Version Requirement</p><p>The plugin uses the <code>experimental.text.complete</code> hook, which is available in OpenCode version 1.0.137+.</p></div><hr><h2 id="problem-2-seeing-invalid-structure-comment" tabindex="-1">Problem 2: Seeing &quot;invalid structure&quot; Comment <a class="header-anchor" href="#problem-2-seeing-invalid-structure-comment" aria-label="Permalink to &quot;Problem 2: Seeing &quot;invalid structure&quot; Comment&quot;">​</a></h2><h3 id="symptoms-1" tabindex="-1">Symptoms <a class="header-anchor" href="#symptoms-1" aria-label="Permalink to &quot;Symptoms&quot;">​</a></h3><p>This comment appears at the end of the table:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&lt;!-- table not formatted: invalid structure --&gt;</span></span></code></pre></div><h3 id="what-is-invalid-table-structure" tabindex="-1">What Is &quot;Invalid Table Structure&quot; <a class="header-anchor" href="#what-is-invalid-table-structure" aria-label="Permalink to &quot;What Is &quot;Invalid Table Structure&quot;&quot;">​</a></h3><p>The plugin validates every Markdown table, and only tables that pass validation are formatted. If the table structure doesn&#39;t conform to specifications, the plugin preserves the original text and adds this comment.</p><h3 id="common-causes" tabindex="-1">Common Causes <a class="header-anchor" href="#common-causes" aria-label="Permalink to &quot;Common Causes&quot;">​</a></h3><h4 id="cause-1-insufficient-table-rows" tabindex="-1">Cause 1: Insufficient Table Rows <a class="header-anchor" href="#cause-1-insufficient-table-rows" aria-label="Permalink to &quot;Cause 1: Insufficient Table Rows&quot;">​</a></h4><p><strong>Error Example</strong>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Name |</span></span></code></pre></div><p>Only 1 row, incomplete format.</p><p><strong>Correct Example</strong>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Name |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">|---|</span></span></code></pre></div><p>At least 2 rows are required (including separator row).</p><h4 id="cause-2-inconsistent-column-count" tabindex="-1">Cause 2: Inconsistent Column Count <a class="header-anchor" href="#cause-2-inconsistent-column-count" aria-label="Permalink to &quot;Cause 2: Inconsistent Column Count&quot;">​</a></h4><p><strong>Error Example</strong>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Name | Age |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">|--- | ---|</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Alice |</span></span></code></pre></div><p>First row has 2 columns, second row has 1 column. Column count is inconsistent.</p><p><strong>Correct Example</strong>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Name | Age |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">|--- | ---|</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Alice | 25 |</span></span></code></pre></div><p>All rows must have the same number of columns.</p><h4 id="cause-3-missing-separator-row" tabindex="-1">Cause 3: Missing Separator Row <a class="header-anchor" href="#cause-3-missing-separator-row" aria-label="Permalink to &quot;Cause 3: Missing Separator Row&quot;">​</a></h4><p><strong>Error Example</strong>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Name | Age |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Alice | 25 |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Bob | 30 |</span></span></code></pre></div><p>No separator row like <code>|---|---|</code>.</p><p><strong>Correct Example</strong>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Name | Age |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">|--- | ---|</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Alice | 25 |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Bob | 30 |</span></span></code></pre></div><h3 id="how-to-quickly-diagnose" tabindex="-1">How to Quickly Diagnose <a class="header-anchor" href="#how-to-quickly-diagnose" aria-label="Permalink to &quot;How to Quickly Diagnose&quot;">​</a></h3><p>Use the following checklist:</p><ul><li>[ ] Table has at least 2 rows</li><li>[ ] All rows have the same number of columns (count the number of <code>|</code> in each row)</li><li>[ ] Separator row exists (second row is usually in <code>|---|</code> format)</li></ul><p>If all conditions are met but the error persists, check for hidden characters or extra spaces causing column count calculation errors.</p><hr><h2 id="problem-3-seeing-table-formatting-failed-comment" tabindex="-1">Problem 3: Seeing &quot;table formatting failed&quot; Comment <a class="header-anchor" href="#problem-3-seeing-table-formatting-failed-comment" aria-label="Permalink to &quot;Problem 3: Seeing &quot;table formatting failed&quot; Comment&quot;">​</a></h2><h3 id="symptoms-2" tabindex="-1">Symptoms <a class="header-anchor" href="#symptoms-2" aria-label="Permalink to &quot;Symptoms&quot;">​</a></h3><p>This comment appears at the end of the text:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&lt;!-- table formatting failed: {error message} --&gt;</span></span></code></pre></div><h3 id="cause" tabindex="-1">Cause <a class="header-anchor" href="#cause" aria-label="Permalink to &quot;Cause&quot;">​</a></h3><p>This indicates the plugin threw an unexpected internal exception.</p><h3 id="solution" tabindex="-1">Solution <a class="header-anchor" href="#solution" aria-label="Permalink to &quot;Solution&quot;">​</a></h3><ol><li><strong>Check the error message</strong>: The <code>{error message}</code> part in the comment explains the specific problem</li><li><strong>Check table content</strong>: Confirm if there are extreme special cases (such as very long single lines, special character combinations)</li><li><strong>Preserve original text</strong>: Even if formatting fails, the plugin won&#39;t destroy your original text, your content is safe</li><li><strong>Report the issue</strong>: If the problem repeatedly occurs, you can submit an issue report at <a href="https://github.com/franlol/opencode-md-table-formatter/issues" target="_blank" rel="noreferrer">GitHub Issues</a></li></ol><div class="tip custom-block"><p class="custom-block-title">Error Isolation</p><p>The plugin wraps formatting logic in try-catch, so even if an error occurs, it won&#39;t interrupt the OpenCode workflow.</p></div><hr><h2 id="problem-4-certain-table-types-not-supported" tabindex="-1">Problem 4: Certain Table Types Not Supported <a class="header-anchor" href="#problem-4-certain-table-types-not-supported" aria-label="Permalink to &quot;Problem 4: Certain Table Types Not Supported&quot;">​</a></h2><h3 id="unsupported-table-types" tabindex="-1">Unsupported Table Types <a class="header-anchor" href="#unsupported-table-types" aria-label="Permalink to &quot;Unsupported Table Types&quot;">​</a></h3><h4 id="html-tables" tabindex="-1">HTML Tables <a class="header-anchor" href="#html-tables" aria-label="Permalink to &quot;HTML Tables&quot;">​</a></h4><p><strong>Not Supported</strong>:</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">table</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">th</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Name&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">th</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">td</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Alice&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">td</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">table</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p><strong>Only Supports</strong>: Markdown Pipe Tables</p><h4 id="multi-line-cells" tabindex="-1">Multi-line Cells <a class="header-anchor" href="#multi-line-cells" aria-label="Permalink to &quot;Multi-line Cells&quot;">​</a></h4><p><strong>Not Supported</strong>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Name | Description |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">|--- | ---|</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Alice | Line 1&lt;br&gt;Line 2 |</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Why Not Supported</p><p>The plugin is designed for simple tables generated by AI. Multi-line cells require more complex layout logic.</p></div><h4 id="tables-without-separator-rows" tabindex="-1">Tables Without Separator Rows <a class="header-anchor" href="#tables-without-separator-rows" aria-label="Permalink to &quot;Tables Without Separator Rows&quot;">​</a></h4><p><strong>Not Supported</strong>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Name | Age |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Alice | 25 |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Bob | 30 |</span></span></code></pre></div><p>Must have a separator row (see &quot;Cause 3&quot; above).</p><hr><h2 id="problem-5-tables-still-appear-misaligned-after-formatting" tabindex="-1">Problem 5: Tables Still Appear Misaligned After Formatting <a class="header-anchor" href="#problem-5-tables-still-appear-misaligned-after-formatting" aria-label="Permalink to &quot;Problem 5: Tables Still Appear Misaligned After Formatting&quot;">​</a></h2><h3 id="possible-causes" tabindex="-1">Possible Causes <a class="header-anchor" href="#possible-causes" aria-label="Permalink to &quot;Possible Causes&quot;">​</a></h3><h4 id="cause-1-concealment-mode-not-enabled" tabindex="-1">Cause 1: Concealment Mode Not Enabled <a class="header-anchor" href="#cause-1-concealment-mode-not-enabled" aria-label="Permalink to &quot;Cause 1: Concealment Mode Not Enabled&quot;">​</a></h4><p>The plugin is optimized for OpenCode&#39;s Concealment Mode, which hides Markdown symbols (like <code>**</code>, <code>*</code>).</p><p>If your editor hasn&#39;t enabled concealment mode, tables may appear &quot;misaligned&quot; because Markdown symbols take up actual width.</p><p><strong>Solution</strong>:</p><p>Confirm OpenCode concealment mode is enabled (enabled by default).</p><h4 id="cause-2-excessively-long-cell-content" tabindex="-1">Cause 2: Excessively Long Cell Content <a class="header-anchor" href="#cause-2-excessively-long-cell-content" aria-label="Permalink to &quot;Cause 2: Excessively Long Cell Content&quot;">​</a></h4><p>If a cell&#39;s content is very long, the table may stretch quite wide.</p><p>This is normal behavior. The plugin won&#39;t truncate content.</p><h4 id="cause-3-symbols-in-inline-code" tabindex="-1">Cause 3: Symbols in Inline Code <a class="header-anchor" href="#cause-3-symbols-in-inline-code" aria-label="Permalink to &quot;Cause 3: Symbols in Inline Code&quot;">​</a></h4><p>Markdown symbols in inline code (<code>\`**code**\`</code>) are calculated at <strong>literal width</strong> and won&#39;t be stripped.</p><p><strong>Example</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>| Symbol | Width |</span></span>
<span class="line"><span>|--- | ---|</span></span>
<span class="line"><span>| Normal text | 4 |</span></span>
<span class="line"><span>| \`**bold**\` | 8 |</span></span></code></pre></div><p>This is correct behavior because in concealment mode, symbols inside code blocks are visible.</p><hr><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><p>Through this lesson, you&#39;ve learned:</p><ul><li><strong>Diagnose tables not formatting</strong>: Check configuration, restart, version requirements, separator rows</li><li><strong>Understand invalid table errors</strong>: Row count, column count, separator row validation</li><li><strong>Identify known limitations</strong>: HTML tables, multi-line cells, tables without separator rows not supported</li><li><strong>Quick self-check</strong>: Use checklist to verify table structure</li></ul><hr><h2 id="still-not-resolved" tabindex="-1">Still Not Resolved? <a class="header-anchor" href="#still-not-resolved" aria-label="Permalink to &quot;Still Not Resolved?&quot;">​</a></h2><p>If you&#39;ve checked all the above issues but the problem still exists:</p><ol><li><strong>Check full logs</strong>: The plugin runs silently by default with no detailed logs</li><li><strong>Submit an Issue</strong>: Provide your table example and error message at <a href="https://github.com/franlol/opencode-md-table-formatter/issues" target="_blank" rel="noreferrer">GitHub Issues</a></li><li><strong>Reference advanced lessons</strong>: Read <a href="./../../advanced/table-spec/">Table Specification</a> and <a href="./../../advanced/concealment-mode/">Concealment Mode Principles</a> for more technical details</li></ol><hr><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>Next lesson we&#39;ll learn <strong><a href="./../../appendix/limitations/">Known Limitations: Plugin Boundaries</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>Plugin design boundaries and constraints</li><li>Possible future enhancements</li><li>How to determine if a scenario is suitable for using this plugin</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-26</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File path</th><th>Line number</th></tr></thead><tbody><tr><td>Table validation logic</td><td><a href="https://github.com/franlol/opencode-md-table-formatter/blob/main/index.ts#L70-L88" target="_blank" rel="noreferrer"><code>index.ts</code></a></td><td>70-88</td></tr><tr><td>Table row detection</td><td><a href="https://github.com/franlol/opencode-md-table-formatter/blob/main/index.ts#L58-L61" target="_blank" rel="noreferrer"><code>index.ts</code></a></td><td>58-61</td></tr><tr><td>Separator row detection</td><td><a href="https://github.com/franlol/opencode-md-table-formatter/blob/main/index.ts#L63-L68" target="_blank" rel="noreferrer"><code>index.ts</code></a></td><td>63-68</td></tr><tr><td>Error handling</td><td><a href="https://github.com/franlol/opencode-md-table-formatter/blob/main/index.ts#L15-L20" target="_blank" rel="noreferrer"><code>index.ts</code></a></td><td>15-20</td></tr><tr><td>Invalid table comment</td><td><a href="https://github.com/franlol/opencode-md-table-formatter/blob/main/index.ts#L44-L47" target="_blank" rel="noreferrer"><code>index.ts</code></a></td><td>44-47</td></tr></tbody></table><p><strong>Key Business Rules</strong>:</p><ul><li><code>isValidTable()</code>: Validates that table must have at least 2 rows, all rows have consistent column counts, and a separator row exists (lines 70-88)</li><li><code>isSeparatorRow()</code>: Uses regex <code>/^\\s*:?-+:?\\s*$/</code> to detect separator rows (lines 63-68)</li><li>Column minimum width: 3 characters (line 115)</li></ul><p><strong>Error Handling Mechanism</strong>:</p><ul><li>try-catch wraps the main processing function (lines 15-20)</li><li>Formatting failure: Preserve original text + add <code>&lt;!-- table formatting failed: {message} --&gt;</code> comment</li><li>Validation failure: Preserve original text + add <code>&lt;!-- table not formatted: invalid structure --&gt;</code> comment</li></ul></details>`,119)])])}const m=a(n,[["render",o]]);export{u as __pageData,m as default};
